const burger=document.querySelector(".burger-menu"),listMenu=document.querySelector(".menu__nav"),navLinks=document.querySelectorAll(".menu__link");burger.addEventListener("click",function(){burger.classList.toggle("_active"),document.body.classList.toggle("_lock"),listMenu.classList.toggle("_active")});for(let e=0;e<navLinks.length;e++){const t=navLinks[e];t.addEventListener("click",function(){burger.classList.remove("_active"),document.body.classList.remove("_lock"),listMenu.classList.remove("_active")})}(new WOW).init();